INSERT INTO products (id, category_id, created_at, description, image_url, is_featured, name, price, stock, updated_at, brand, discount, images, original_price, shipping, specifications, tag, warranty, limited_time_price, limited_time_start_at, limited_time_end_at, status, detail_content, free_shipping, free_shipping_threshold, variants) VALUES (1, 10, NULL, 'Programmable automatic feeder with portion control, sealed food storage and a clear schedule for cats and small dogs.', 'https://images.unsplash.com/photo-1589924691995-400dc9ecc119?auto=format&fit=crop&w=900&q=80', true, 'PawPilot Smart Pet Feeder 4L', 129.90, 94, '2026-05-12T06:09:19.940304', 'PawPilot', 19, '["https://images.unsplash.com/photo-1601758123927-1967a0d5f11b?auto=format&fit=crop&w=900&q=80","https://images.unsplash.com/photo-1595433707802-6b2626ef1c91?auto=format&fit=crop&w=900&q=80"]', 159.90, 'Ships in a protective box; free over threshold.', '{"Pet Size":"Small, Medium","Capacity":"4 L","Material":"BPA-free ABS","Color":"White","i18n.es.name":"Comedero inteligente PawPilot 4L","i18n.es.description":"Comedero automatico programable con control de porciones para gatos y perros pequenos.","options.Size":"Small,Medium","options.Color":"White,Black"}', 'hot', '1 year limited warranty', 109.90, '2026-05-01T00:00', '2026-06-30T23:59:59', 'ACTIVE', '[{"type":"text","content":"Set up to six meals per day and keep dry food fresh with the sealed hopper."},{"type":"text","content":"English is the default content. Spanish and Chinese demo text is stored in specifications for language fallback testing."}]', true, 899.00, NULL);
